// Custom Runtime Exceptionclass CargoSafetyException extends RuntimeException {    public CargoSafetyException(String message) {        super(message);    }}// Bogie classclass GoodsBogie {    private String shape;    private String cargo;    public GoodsBogie(String shape) {        this.shape = shape;    }    public void assignCargo(String cargo) {        try {            // Validation logic            if (shape.equalsIgnoreCase("Rectangular") && cargo.equalsIgnoreCase("Petroleum")) {                throw new CargoSafetyException("Unsafe Assignment: Petroleum cannot be assigned to a Rectangular bogie!");            }            this.cargo = cargo;            System.out.println("Cargo '" + cargo + "' successfully assigned to " + shape + " bogie.");        } catch (CargoSafetyException e) {            // Exception handling            System.err.println("Error: " + e.getMessage());        } finally {            // Cleanup / Logging            System.out.println("Validation completed for cargo assignment on " + shape + " bogie.");        }    }    public String getCargo() {        return cargo;    }}// Test Applicationpublic class TrainConsistManagementApp {    public static void main(String[] args) {        // Safe assignment        GoodsBogie cylindricalBogie = new GoodsBogie("Cylindrical");        cylindricalBogie.assignCargo("Petroleum");  // Safe        // Unsafe assignment        GoodsBogie rectangularBogie = new GoodsBogie("Rectangular");        rectangularBogie.assignCargo("Petroleum");  // Unsafe        // Program continues safely        GoodsBogie squareBogie = new GoodsBogie("Square");        squareBogie.assignCargo("Coal");  // Safe    }}